#include<bits/stdc++.h>using namespace std;int t,n,p[110],v[110],ans=0,f=0;void dfs(int x){	if(x==n+1){		ans++;		if(ans>n){			f=1;return;		}		for(int i=1;i<=n;i++) cout<<p[i]<<' ';		cout<<endl;	}	for(int i=1;i<=n;i++){		if(x==1){			if(v[i]==0){				v[i]=1;				p[x]=i;				dfs(x+1);				v[i]=0;			}		}else{			if(v[i]==0&&p[x-1]+p[x-2]!=i){				v[i]=1;				p[x]=i;				dfs(x+1);				v[i]=0;			}		}		if(f==1) return;	}}int main(){	cin>>t;	while(t--){		cin>>n;		dfs(1);		ans=0;f=0;	}		return 0;}